let currentLang = localStorage.getItem('ec_lang') || 'zh';

// Async load additional vocab translations
const VOCAB_EXTRA = {};
fetch('/vocab_meanings.json?v=' + Date.now()).then(r => r.json()).then(d => {
  Object.assign(VOCAB_EXTRA, d);
  // Re-render current HSK view with translations
  if (hskLevel > 0) loadHSK(hskLevel);
  else if (typeof loadThemedVocab === 'function') loadThemedVocab();
}).catch(() => {});

function getVm(w) {
  const lang = currentLang;
  if (lang === 'en') return w.meaning;
  if (lang === 'zh') return w.hanzi;
  return VOCAB_EXTRA[lang]?.[w.meaning] || VOCAB_MEANINGS[lang]?.[w.meaning] || '';
}

function t(key) {
  return LANG[currentLang]?.[key] || key;
}

function switchLang(lang) {
  currentLang = lang;
  localStorage.setItem('ec_lang', lang);
  document.documentElement.lang = lang === 'zh' ? 'zh-CN' : lang === 'vi' ? 'vi' : 'en';
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const raw = el.dataset.i18n;
    const m = raw.match(/^\[(\w+)\](.+)/);
    if (m) {
      const [, attr, key] = m;
      const val = t(key);
      if (attr === 'html') {
        el.innerHTML = val;
      } else {
        el.setAttribute(attr, val);
      }
    } else {
      el.innerHTML = t(raw);
    }
  });
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    const key = el.dataset.i18nPh;
    el.placeholder = t(key);
  });
  document.querySelectorAll('.lang-option').forEach(el => {
    el.classList.toggle('active', el.dataset.lang === lang);
  });
  const sel = document.getElementById('profileLangSelect');
  if (sel) sel.value = lang;
  updateHomeStats();
  updateStreakUI();
  document.dispatchEvent(new CustomEvent('langchange', {detail: {lang}}));
}

document.addEventListener('DOMContentLoaded', () => {
  switchLang(currentLang);
});


