// ===== HSK VOCABULARY =====
function loadHSK(level){
  if(hskLevel===0) return;
  hskLevel = level;
  document.querySelectorAll('.hsk-tab').forEach(t=>{
    t.style.background = parseInt(t.dataset.hsk)===level?'linear-gradient(135deg,var(--primary),var(--primary-dark))':'';
    t.style.color = parseInt(t.dataset.hsk)===level?'#fff':'';
  });
  const themedBtn = document.querySelector('[data-themed="true"]');
  if(themedBtn){themedBtn.style.background='';themedBtn.style.color='';}
  // Show loading spinner
  const tb = document.getElementById('hskBody');
  if(tb) tb.innerHTML = '<tr><td colspan="5"><div class="spinner-container"><div class="spinner"></div><div class="spinner-text">' + t('app.loading') + '</div></div></td></tr>';
  const data = HSK_DATA[level]||[];
  currentVocabData = data;
  // Reset search
  const si = document.getElementById('hskSearch');
  if(si) si.value = '';
  if(data.length===0){renderVocabTable([]);return;}
  setTimeout(()=>renderVocabTable(data), 300);
}

// Debounced search
let searchTimer;
function filterHSK(){
  clearTimeout(searchTimer);
  searchTimer = setTimeout(() => {
  const q = (document.getElementById('hskSearch')?.value || '').toLowerCase().trim();
  if(!q){ renderVocabTable(currentVocabData); return; }
  const filtered = currentVocabData.filter(w =>
    w.hanzi.includes(q) ||
    w.pinyin.toLowerCase().includes(q) ||
    w.meaning.toLowerCase().includes(q)
  );
  renderVocabTable(filtered);
  }, 150);
}

const THEME_KEYS = ['food','travel','shopping','daily','health','nature','colors','time'];
function loadThemedVocab(){
  document.querySelectorAll('.hsk-tab').forEach(t=>{t.style.background='';t.style.color='';});
  const themedBtn = document.querySelector('[data-themed="true"]');
  if(themedBtn){themedBtn.style.background='linear-gradient(135deg,var(--primary),var(--primary-dark))';themedBtn.style.color='#fff';}
  const cats = THEMED_VOCAB.map((c,i)=>`<button class="btn btn-secondary btn-sm themed-cat-tab" data-cat="${i}" onclick="loadThemedCategory(${i})">${t('theme.'+THEME_KEYS[i])}</button>`).join('');
  const tb = document.getElementById('hskBody');
  if(tb) tb.innerHTML = `<tr><td colspan="5"><div style="display:flex;gap:8px;flex-wrap:wrap;padding:8px 0">${cats}</div><div id="themedVocabArea" style="margin-top:12px;text-align:center;color:var(--text3);padding:20px">${t('hsk.select_hint')}</div></td></tr>`;
}
function loadThemedCategory(idx){
  const cat = THEMED_VOCAB[idx];
  currentVocabData = cat.words;
  hskLevel = 0;
  document.querySelectorAll('.themed-cat-tab').forEach(t=>{
    t.style.background=parseInt(t.dataset.cat)===idx?'linear-gradient(135deg,var(--primary),var(--primary-dark))':'';
    t.style.color=parseInt(t.dataset.cat)===idx?'#fff':'';
  });
  const si = document.getElementById('hskSearch');
  if(si) si.value = '';
  renderVocabTable(cat.words);
}
function renderVocabTable(data){
  const tb = document.getElementById('hskBody');
  if(!tb) return;
  if(data.length===0){tb.innerHTML='<tr><td colspan="5" style="text-align:center;padding:24px;color:var(--text3)">'+t('hsk.no_words')+'</td></tr>';return;}
  tb.innerHTML = data.map((w,i)=>{
    const saved=savedWords.includes(w.hanzi);
    return `<tr><td style="color:var(--text3);font-size:12px">${i+1}</td><td class="v-hanzi">${w.hanzi}<span class="sp-btn" onclick="speakPinyin('${w.hanzi}')">🔊</span></td><td class="v-pinyin">${w.pinyin}</td><td class="v-meaning">${getVm(w)}</td><td><span style="cursor:pointer;font-size:18px" onclick="toggleSaveWord('${w.hanzi}')">${saved?'⭐':'☆'}</span></td></tr>`;
  }).join('');
}
function toggleSaveWord(hanzi){
  const idx = savedWords.indexOf(hanzi);
  if(idx>-1) savedWords.splice(idx,1); else savedWords.push(hanzi);
  localStorage.setItem('ec_saved',JSON.stringify(savedWords));
  syncToServer();
  toast(savedWords.includes(hanzi)?`⭐ ${t('hsk.save')}: ${hanzi}`:`✕ ${hanzi}`, savedWords.includes(hanzi)?'success':'info');
  if(hskLevel>0) loadHSK(hskLevel); else loadThemedVocab();
  updateHomeStats();
  updateSidebarUserInfo();
  // Auto level-up: if all words in current HSK level saved, upgrade
  if (hskLevel > 0 && hskLevel < 6) {
    const levelWords = HSK_DATA[hskLevel] || [];
    const allSaved = levelWords.every(w => savedWords.includes(w.hanzi));
    if (allSaved && savedWords.includes(hanzi)) {
      const nextLv = hskLevel + 1;
      hskLevel = nextLv;
      localStorage.setItem('hskLevel', String(nextLv));
      toast('🎉 升级！已自动升级到 HSK ' + nextLv, 'success');
      loadHSK(nextLv);
    }
  }
}

// ===== FLASHCARD =====
function showFlashcardMode(){
  fcData = [...(HSK_DATA[1]||[]),...(HSK_DATA[2]||[]),...(HSK_DATA[3]||[]),...(HSK_DATA[4]||[]),...(HSK_DATA[5]||[])].sort(()=>Math.random()-.5).slice(0,200);
  fcIndex=0;
  const area = document.getElementById('flashcardArea');
  if(area) area.classList.remove('hidden');
  renderFlashcard();
  navigateTo('practice');
}
function renderFlashcard(){
  const v = fcData[fcIndex]; if(!v) return;
  ['fcFront','fcBackChar','fcPinyin','fcMeaning','fcCounter'].forEach(id=>{
    const el = document.getElementById(id);
    if(!el) return;
    if(id==='fcFront') el.textContent=v.hanzi;
    else if(id==='fcBackChar') el.textContent=v.hanzi;
    else if(id==='fcPinyin') el.textContent=v.pinyin;
    else if(id==='fcMeaning') el.textContent=getVm(v);
    else if(id==='fcCounter') el.textContent=`${fcIndex+1}/${fcData.length}`;
  });
  const fc = document.getElementById('flashcardEl');
  if(fc) fc.classList.remove('flipped');
}
function toggleFlashcard(){document.getElementById('flashcardEl')?.classList.toggle('flipped');}
function prevFlashcard(){fcIndex=(fcIndex-1+fcData.length)%fcData.length;renderFlashcard();}
function nextFlashcard(){fcIndex=(fcIndex+1)%fcData.length;renderFlashcard();}

// ===== QUIZ =====
function startHSKQuiz(){
  const level = hskLevel||1;
  const pool = HSK_DATA[level]?.slice()||HSK_DATA[1]?.slice()||[];
  if(pool.length===0){toast(t('quiz.no_vocab'),'error');return;}
  const shuffled = pool.sort(()=>Math.random()-.5).slice(0,10);
  const questions = shuffled.map(v => {
    const wrong = pool.filter(x=>x.hanzi!==v.hanzi).sort(()=>Math.random()-.5).slice(0,3);
    const opts = [{text:getVm(v),correct:true},...wrong.map(w=>({text:getVm(w),correct:false}))].sort(()=>Math.random()-.5);
    return {hanzi:v.hanzi,pinyin:v.pinyin,options:opts,answered:false,selected:-1};
  });
  quizState={questions,idx:0,score:0,done:false};
  document.getElementById('quizArea')?.classList.remove('hidden');
  renderQuiz();
  navigateTo('practice');
}
function startToneQuiz(){
  // Build pool from all HSK words that have pinyin with identifiable tones
  const allWords = [...Object.values(HSK_DATA).flat(), ...THEMED_VOCAB.flatMap(c=>c.words)];
  // Only use single-character words for tone quiz (multi-syllable has mixed tones)
  const pool = allWords.filter(w => !w.pinyin.includes(' ') && /[āáǎàēéěèīíǐìōóǒòūúǔùǖǘǚǜ]/.test(w.pinyin));
  // Shuffle and pick 10
  const chars = pool.sort(()=>Math.random()-.5).slice(0,10).map(w => {
    // Extract first tone number from pinyin
    const toneMatch = w.pinyin.match(/[āáǎàēéěèīíǐìōóǒòūúǔùǖǘǚǜ]/);
    if (!toneMatch) return null;
    const toneMap = {
      'ā':1,'á':2,'ǎ':3,'à':4,
      'ē':1,'é':2,'ě':3,'è':4,
      'ī':1,'í':2,'ǐ':3,'ì':4,
      'ō':1,'ó':2,'ǒ':3,'ò':4,
      'ū':1,'ú':2,'ǔ':3,'ù':4,
      'ǖ':1,'ǘ':2,'ǚ':3,'ǜ':4,
    };
    return {hanzi:w.hanzi, pinyin:w.pinyin, tone:toneMap[toneMatch[0]] || 1};
  }).filter(Boolean);
  const questions = chars.map(v => {
    const tones=[1,2,3,4];
    function applyTone(py, t) {
      // Handle multi-syllable pinyin (space-separated)
      return py.split(' ').map(syl => {
        if (!syl) return syl;
        const toneMarks = {a:['ā','á','ǎ','à'],o:['ō','ó','ǒ','ò'],e:['ē','é','ě','è'],i:['ī','í','ǐ','ì'],u:['ū','ú','ǔ','ù'],ü:['ǖ','ǘ','ǚ','ǜ']};
        let vowel = '';
        if (syl.includes('a')) vowel = 'a';
        else if (syl.includes('e')) vowel = 'e';
        else if (syl.includes('ou')) vowel = 'o';
        else { for (const v of ['ü','u','i','o']) { if (syl.includes(v)) { vowel = v; break; } } }
        if (!vowel) return syl;
        return syl.replace(vowel, toneMarks[vowel]?.[t-1] || vowel);
      }).join(' ');
    }
    const opts = tones.map(t => {
      // Strip existing tone marks from pinyin to get plain pinyin
      const plain = v.pinyin.replace(/[āáǎàēéěèīíǐìōóǒòūúǔùǖǘǚǜ]/g, m => {
        const map = {ā:'a',á:'a',ǎ:'a',à:'a',ē:'e',é:'e',ě:'e',è:'e',ī:'i',í:'i',ǐ:'i',ì:'i',ō:'o',ó:'o',ǒ:'o',ò:'o',ū:'u',ú:'u',ǔ:'u',ù:'u',ǖ:'ü',ǘ:'ü',ǚ:'ü',ǜ:'ü'};
        return map[m] || m;
      });
      return {text: t + ' (' + applyTone(plain, t) + ')', correct: t === v.tone};
    }).sort(()=>Math.random()-.5);
    return {hanzi:v.hanzi,pinyin:v.pinyin,options:opts,answered:false,selected:-1};
  });
  quizState={questions,idx:0,score:0,done:false};
  document.getElementById('quizArea')?.classList.remove('hidden');
  renderQuiz();
  navigateTo('practice');
}
function renderQuiz(){
  const card = document.getElementById('quizCard'); if(!card||!quizState) return;
  const {questions,idx,done}=quizState;
  if(done){
    const pct=Math.round(quizState.score/questions.length*100);
    const msg=pct===100?t('practice.perfect') : pct>=70?t('practice.good') : t('practice.keep_going');
    card.innerHTML=`<div style="text-align:center;padding:20px"><div style="font-size:56px;font-weight:900;background:linear-gradient(135deg,var(--primary),var(--accent));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text">${quizState.score}/${questions.length}</div><div style="color:var(--text3);margin:8px 0 16px">${pct}% ${t('quiz.correct_rate')}</div><div style="font-size:18px;margin-bottom:20px">${msg}</div><button class="btn btn-primary" onclick="document.getElementById('quizArea').classList.add('hidden')">${t('practice.close')}</button></div>`;
    return;
  }
  const q=questions[idx];
  const dots=questions.map((q,i)=>{let c='quiz-dot';if(q.answered)c+=q.selected>=0&&q.options[q.selected].correct?' correct':' wrong';if(i===idx)c+=' current';return `<div class="${c}"></div>`;}).join('');
  const opts=q.options.map((o,i)=>{let c='quiz-opt';if(q.answered){if(o.correct)c+=' correct';else if(i===q.selected)c+=' wrong';}return `<button class="${c}" data-oi="${i}" ${q.answered?'disabled':''}>${o.text}</button>`;}).join('');
  card.innerHTML=`<div class="quiz-progress">${dots}</div><div style="text-align:center;margin-bottom:16px"><div class="quiz-question"><div class="q-char">${q.hanzi}</div><div class="q-hint">${q.pinyin}</div></div></div><div class="quiz-options">${opts}</div>${q.answered?`<div style="text-align:center;margin-top:16px"><button class="btn btn-primary" onclick="nextQuizQ()">${idx<questions.length-1?t('practice.next'):t('practice.result')}</button></div>`:''}`;
  if(!q.answered) card.querySelectorAll('.quiz-opt').forEach(el=>{el.addEventListener('click',()=>{const oi=parseInt(el.dataset.oi);if(q.answered)return;q.selected=oi;q.answered=true;if(q.options[oi].correct)quizState.score++;renderQuiz();});});
}
function nextQuizQ(){
  quizState.idx++;
  if(quizState.idx>=quizState.questions.length){quizState.done=true;quizCount++;localStorage.setItem('ec_quizCount',quizCount);syncToServer();syncQuizResult(String(hskLevel||1),quizState.score,quizState.questions.length);}
  renderQuiz();updateHomeStats();
}

// ===== AUTH SYSTEM (Server-side) =====
// 只在本地存 token，用户数据全在服务器
const auth = {
  token: localStorage.getItem('ec_token') || null,
  current: JSON.parse(localStorage.getItem('ec_user') || 'null'),
};

function saveAuth() {
  if (auth.token) {
    localStorage.setItem('ec_token', auth.token);
    localStorage.setItem('ec_user', JSON.stringify(auth.current));
  } else {
    localStorage.removeItem('ec_token');
    localStorage.removeItem('ec_user');
  }
}

function isLoggedIn() {
  return auth.token !== null && auth.current !== null;
}

function getCurrentUser() {
  return auth.current;
}

// ===== CROSS-DEVICE DATA SYNC =====
function syncToServer() {
  if (!isLoggedIn()) return;
  // Sync via key-value store (legacy)
  const data = {
    ec_saved: JSON.stringify(savedWords),
    ec_streak: JSON.stringify(streakData),
    ec_quizCount: String(quizCount),
  };
  fetch('/api/sync', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token: auth.token, data: data })
  }).catch(() => {});
  // Sync saved words to structured table
  fetch('/api/sync/saved-words', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token: auth.token, words: savedWords })
  }).catch(() => {});
}

function syncCheckin() {
  if (!isLoggedIn()) return;
  fetch('/api/sync/checkin', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token: auth.token })
  }).catch(() => {});
}

function syncQuizResult(level, score, total) {
  if (!isLoggedIn()) return;
  fetch('/api/sync/quiz', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token: auth.token, level: level, score: score, total: total })
  }).catch(() => {});
}

function syncFromServer() {
  if (!isLoggedIn()) return Promise.resolve();
  // Use new progress API
  return fetch('/api/progress?token=' + encodeURIComponent(auth.token))
    .then(r => r.json())
    .then(resp => {
      if (!resp.ok) return;
      if (resp.saved_words && resp.saved_words.length > savedWords.length) {
        savedWords = resp.saved_words;
        localStorage.setItem('ec_saved', JSON.stringify(savedWords));
      }
      if (resp.checkins && resp.checkins.length > 0) {
        streakData = { count: resp.streak || resp.checkins.length, dates: resp.checkins, last: resp.checkins[resp.checkins.length - 1] };
        localStorage.setItem('ec_streak', JSON.stringify(streakData));
      }
      if (resp.quizzes && resp.quizzes.length > 0) {
        quizCount = resp.quizzes.length;
        localStorage.setItem('ec_quizCount', String(quizCount));
      }
    })
    .catch(() => {});
}

function syncOnLogin() {
  // Load server data and merge into local
  syncFromServer().then(() => {
    // Then push any local data that might be newer
    syncToServer();
    updateStreakUI();
    updateHomeStats();
  });
}

function openLogin() {
  document.getElementById('loginOverlay').style.display = 'flex';
  document.getElementById('loginError').style.display = 'none';
  document.getElementById('regError').style.display = 'none';
}

function closeLogin() {
  document.getElementById('loginOverlay').style.display = 'none';
}

function showRegister() {
  document.getElementById('loginForm').style.display = 'none';
  document.getElementById('registerForm').style.display = 'block';
  document.getElementById('regError').style.display = 'none';
}

function showLogin() {
  document.getElementById('loginForm').style.display = 'block';
  document.getElementById('registerForm').style.display = 'none';
  document.getElementById('loginError').style.display = 'none';
}

function doLogin() {
  const user = document.getElementById('loginUser').value.trim();
  const pass = document.getElementById('loginPass').value.trim();
  const err = document.getElementById('loginError');
  if (!user || !pass) { err.textContent = t('err.fill_fields'); err.style.display = 'block'; return; }

  fetch('/api/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ username: user, password: pass })
  })
  .then(r => r.json())
  .then(data => {
    if (data.ok) {
      auth.token = data.token;
      auth.current = { username: data.username };
      saveAuth();
      closeLogin();
      renderAuthUI();
      updateHomeStats();
      syncOnLogin();
      toast(t('toast.login_ok').replace('{name}', data.username), 'success');
    } else {
      err.textContent = data.error || t('err.wrong_creds');
      err.style.display = 'block';
    }
  })
  .catch(() => {
    err.textContent = t('err.server_down');
    err.style.display = 'block';
  });
}

function doRegister() {
  const user = document.getElementById('regUser').value.trim();
  const pass = document.getElementById('regPass').value.trim();
  const confirm = document.getElementById('regConfirm').value.trim();
  const err = document.getElementById('regError');
  if (!user || !pass) { err.textContent = t('err.fill_fields'); err.style.display = 'block'; return; }
  if (pass !== confirm) { err.textContent = t('err.pass_mismatch'); err.style.display = 'block'; return; }
  if (pass.length < 3) { err.textContent = t('err.pass_short'); err.style.display = 'block'; return; }

  fetch('/api/register', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ username: user, password: pass })
  })
  .then(r => r.json())
  .then(data => {
    if (data.ok) {
      auth.token = data.token;
      auth.current = { username: data.username };
      saveAuth();
      closeLogin();
      renderAuthUI();
      updateHomeStats();
      toast(t('toast.register_ok').replace('{name}', data.username), 'success');
    } else {
      err.textContent = data.error || t('err.register_fail');
      err.style.display = 'block';
    }
  })
  .catch(() => {
    err.textContent = t('err.server_down');
    err.style.display = 'block';
  });
}

function logout() {
  auth.token = null;
  auth.current = null;
  saveAuth();
  renderAuthUI();
  toast(t('toast.logout_ok'), 'info');
}

