// ===== AI CHAT FUNCTIONS =====
let chatHistory = [];
// Force deepseek — siliconflow key is invalid
localStorage.removeItem('chatModel');
let chatModel = 'deepseek';

function toggleChatModel() {
  if (chatModel === 'siliconflow') {
    chatModel = 'deepseek';
    localStorage.setItem('chatModel', 'deepseek');
    toast('丝路极速 AI', 'info');
  } else {
    chatModel = 'siliconflow';
    localStorage.setItem('chatModel', 'siliconflow');
    toast('丝路智联 AI', 'info');
  }
}

function clearChat(){
  chatHistory = [];
  localStorage.removeItem('chatHistory');
  const msgs = document.getElementById('chatMessages');
  if(msgs) msgs.querySelectorAll('.chat-msg').forEach(el=>el.remove());
}

function toggleChat() {
  const sidebar = document.getElementById('chatSidebar');
  const btn = document.getElementById('chatToggleBtn');
  const overlay = document.getElementById('chatOverlay');
  const isOpen = sidebar.classList.contains('open');
  if (isOpen) {
    sidebar.classList.remove('open');
    btn.classList.remove('hidden');
    overlay.classList.remove('open');
  } else {
    sidebar.classList.add('open');
    btn.classList.add('hidden');
    overlay.classList.add('open');
    // Load existing chat history
    loadChatHistory();
    setTimeout(() => {
      document.getElementById('chatInput')?.focus();
    }, 350);
  }
}

function loadChatHistory() {
  try {
    const saved = localStorage.getItem('chatHistory');
    if (saved) {
      chatHistory = JSON.parse(saved);
      // Render saved messages into the DOM
      renderChatHistory();
    }
  } catch(e) { chatHistory = []; }
}

function renderChatHistory() {
  const msgs = document.getElementById('chatMessages');
  if (!msgs) return;
  msgs.querySelectorAll('.chat-msg').forEach(el => el.remove());
  if (chatHistory.length === 0) return;
  for (const entry of chatHistory) {
    const div = document.createElement('div');
    div.className = 'chat-msg ' + (entry.role === 'user' ? 'user' : 'assistant');
    div.textContent = entry.content;
    msgs.appendChild(div);
  }
  msgs.scrollTop = msgs.scrollHeight;
}

function sendChatMessage(msg) {
  const input = document.getElementById('chatInput');
  const text = msg || input.value.trim();
  if (!text) return;

  if (!msg) input.value = '';
  const sendBtn = document.getElementById('chatSendBtn');
  sendBtn.disabled = true;

  const msgs = document.getElementById('chatMessages');
  const userDiv = document.createElement('div');
  userDiv.className = 'chat-msg user';
  userDiv.textContent = text;
  msgs.appendChild(userDiv);
  msgs.scrollTop = msgs.scrollHeight;

  const aiDiv = document.createElement('div');
  aiDiv.className = 'chat-msg assistant';
  aiDiv.innerHTML = '<span class="msg-typing">...</span>';
  msgs.appendChild(aiDiv);
  msgs.scrollTop = msgs.scrollHeight;

  chatHistory.push({ role: 'user', content: text });

  // Call API
  fetch('/api/chat', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      message: text,
      history: chatHistory.slice(-20),
      level: localStorage.getItem('hskLevel') || '',
      savedWords: (JSON.parse(localStorage.getItem('ec_saved')||'[]')).join(','),
      provider: chatModel
    })
  })
  .then(response => {
    if (!response.ok) throw new Error('HTTP ' + response.status);
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let fullText = '';
    let buffer = '';

    function processChunk() {
      reader.read().then(({ done, value }) => {
        if (done) {
          chatHistory.push({ role: 'assistant', content: fullText });
          try { localStorage.setItem('chatHistory', JSON.stringify(chatHistory.slice(-50))); } catch(e) {}
          sendBtn.disabled = false;
          return;
        }
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        let currentEvent = '';
        for (const line of lines) {
          if (line.startsWith('event: ')) {
            currentEvent = line.slice(7).trim();
            continue;
          }
          if (line.startsWith('data: ')) {
            try {
              const data = JSON.parse(line.slice(6));
              if (currentEvent === 'error') {
                aiDiv.className = 'chat-msg error';
                aiDiv.textContent = '请求失败: ' + (data.message || '未知错误');
                sendBtn.disabled = false;
                var chatInputEl = document.getElementById('chatInput');
                if (chatInputEl) chatInputEl.focus();
                return;
              }
              if (data.text) {
                fullText += data.text;
                aiDiv.textContent = fullText;
                msgs.scrollTop = msgs.scrollHeight;
              }
              currentEvent = '';
            } catch(e) { currentEvent = ''; }
          }
        }
        processChunk();
      }).catch(err => {
        aiDiv.className = 'chat-msg error';
        aiDiv.textContent = '连接中断: ' + err.message;
        sendBtn.disabled = false;
      });
    }
    processChunk();
  })
  .catch(err => {
    aiDiv.className = 'chat-msg error';
    aiDiv.textContent = '请求失败: ' + err.message;
    sendBtn.disabled = false;
  });
}

